1	type Quote = { premium: number };
2	type Item = {
3	  type: string;
4	  material?: string;
5	  cursed?: boolean;
6	  enchantment?: number;
7	};
8	type QuoteInput = {
9	  customer?: { yearsWithMHPCO: number };
10	  firstInsurance?: boolean;
11	  followUp?: boolean;
12	  items: Item[];
13	};
14	
15	const PROCESSING_FEE = 5;
16	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
17	  sword: 100,
18	  staff: 80,
19	  amulet: 60,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	const ALIKE_BLOCK_SIZE = 3;
25	const ALIKE_BLOCK_PREMIUM = 60;
26	const CURSE_SURCHARGE_RATE = 0.5;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
29	const LOYALTY_YEARS_THRESHOLD = 2;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
32	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
33	
34	const basePremiumFor = (item: Item): number => {
35	  const basePremium = BASE_PREMIUM_BY_TYPE[item.type];
36	  if (basePremium === undefined) {
37	    throw new Error(`Unknown item type: ${item.type}`);
38	  }
39	  return basePremium;
40	};
41	
42	const curseSurchargeRateFor = (item: Item): number =>
43	  item.cursed ? CURSE_SURCHARGE_RATE : 0;
44	
45	const enchantmentSurchargeRateFor = (item: Item): number =>
46	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
47	    ? HIGH_ENCHANTMENT_SURCHARGE_RATE
48	    : 0;
49	
50	const totalSurchargeRateFor = (item: Item): number =>
51	  curseSurchargeRateFor(item) + enchantmentSurchargeRateFor(item);
52	
53	const itemPremiumFor = (item: Item): number =>
54	  basePremiumFor(item) * (1 + totalSurchargeRateFor(item));
55	
56	const sumItemPremiums = (items: Item[]): number =>
57	  items.reduce((sum, item) => sum + itemPremiumFor(item), 0);
58	
59	const isAlikeBlock = (items: Item[]): boolean =>
60	  items.length === ALIKE_BLOCK_SIZE &&
61	  items.every((item) => item.type === items[0].type);
62	
63	const componentsPremium = (items: Item[]): number =>
64	  isAlikeBlock(items) ? ALIKE_BLOCK_PREMIUM : sumItemPremiums(items);
65	
66	const loyaltyDiscountRateFor = (input: QuoteInput): number =>
67	  (input.customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD
68	    ? LOYALTY_DISCOUNT_RATE
69	    : 0;
70	
71	const firstInsuranceSurchargeRateFor = (input: QuoteInput): number =>
72	  input.firstInsurance ? FIRST_INSURANCE_SURCHARGE_RATE : 0;
73	
74	const followUpDiscountRateFor = (input: QuoteInput): number =>
75	  input.followUp ? FOLLOW_UP_DISCOUNT_RATE : 0;
76	
77	const policyAdjustmentRateFor = (input: QuoteInput): number =>
78	  firstInsuranceSurchargeRateFor(input) -
79	  loyaltyDiscountRateFor(input) -
80	  followUpDiscountRateFor(input);
81	
82	export const quote = (input: QuoteInput): Quote => {
83	  const componentsTotal = componentsPremium(input.items);
84	  const policyTotal = componentsTotal + componentsTotal * policyAdjustmentRateFor(input);
85	  return { premium: Math.ceil(policyTotal + PROCESSING_FEE) };
86	};
87	
88	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
89	  sword: 1000,
90	  amulet: 600,
91	  staff: 800,
92	  potion: 400,
93	  rune: 250,
94	  moonstone: 250,
95	};
96	const DEDUCTIBLE = 100;
97	const FULL_REIMBURSEMENT_RATE = 1;
98	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
99	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
100	const CAP_MULTIPLIER = 2;
101	
102	type Damage = { itemType: string; amount: number };
103	type ClaimInput = {
104	  policy: { items: Item[] };
105	  incident: { damages: Damage[] };
106	};
107	type ClaimResult = { payout: number; remainingCap: number };
108	
109	const reimbursementRateFor = (item: Item): number =>
110	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
111	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
112	    : FULL_REIMBURSEMENT_RATE;
113	
114	const insuranceValueFor = (item: Item): number =>
115	  INSURANCE_VALUE_BY_TYPE[item.type];
116	
117	const policyCoverageCap = (items: Item[]): number =>
118	  CAP_MULTIPLIER * items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
119	
120	const findInsuredItem = (items: Item[], itemType: string): Item =>
121	  items.find((item) => item.type === itemType)!;
122	
123	const payoutFor = (item: Item, damage: Damage): number =>
124	  damage.amount * reimbursementRateFor(item) - DEDUCTIBLE;
125	
126	export const claim = (input: ClaimInput): ClaimResult => {
127	  const damage = input.incident.damages[0];
128	  const damagedItem = findInsuredItem(input.policy.items, damage.itemType);
129	  const rawPayout = payoutFor(damagedItem, damage);
130	  const cap = policyCoverageCap(input.policy.items);
131	  const payout = Math.min(rawPayout, cap);
132	  return { payout, remainingCap: cap - payout };
133	};
